var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"14:13 ARC-KP1\\n센트럴 브릿지 인근, 사건 현장\\n<color=#ff3636>사건 발생</color>, 14시간 경과","JPN":"14:13 ARC-KP1\\nセントラルブリッジ付近、事件現場\\n<color=#ff3636>事件発生から</color>、14時間経過","ENG":"14:13 ARC-KP1\\nNear Central Bridge, Place of Incident\\n14 hours after <color=#ff3636>Incident</color>.","TWN":"14:13 ARC-KP1\\n中央大橋附近 案發現場\\n<color=#ff3636>事件發生</color>後經過14個小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"세실리아 씨, 저기가 사건 현장인가 봐요.","JPN":"セシリアさん、あそこが事件現場のようです。","ENG":"Cecilia, that must be the crime scene.","TWN":"賽希莉亞，那裡似乎就是案發現場。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지, 지아야. 경비가 저렇게 삼엄한데 어떻게 하려고.","JPN":"ユ、ユイちゃん。あんなに警備が堅いのに、どうするつもり？","ENG":"J-Jia. Look at all the guards over there. What are you going to do?","TWN":"小佳，那裡守備很森嚴欸，怎麼辦？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"설마 저들에게 잠시 조사할 수 있게 해 달라고 양해라도 구할 셈이냐?","JPN":"まさか彼らにしばらく調べさせてほしいとでも頼むつもりなの？","ENG":"You’re not thinking of going up to them and asking for their cooperation, are you?","TWN":"你應該不是想要拜託他們讓你調查一下吧？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 여기서는 강행 돌파로 가죠.","JPN":"いいえ、ここは強行突破でいきましょう。","ENG":"No. We’re going to charge right in.","TWN":"當然不是，我要強行突破。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 뭐라고?!","JPN":"な、何ですって！？","ENG":"W-what?!","TWN":"什…什麼？！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지아야! 도와주겠다고 했다만 나는 카운터가 아니라……!!","JPN":"ユイちゃん！　手伝うとは言ったけど、私はカウンターじゃなくて……！！","ENG":"Jia! I told you I was going to help, but I’m not a Counter...!!","TWN":"小佳！我是說過要幫你，但我只是一介平凡人……！！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"증강 현실 활성화!","JPN":"拡張現実、活性化！","ENG":"Activate Augmented Reality!","TWN":"啟動擴增實境！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_ENERGY_CHARGE"},{"id":"L28_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_A","text":{"KOREA":"응? 저, 저기 용의자다! 용의자가 나타났다!!","JPN":"うん？　あ、あそこに容疑者が！　容疑者が現れた！！","ENG":"Huh?! That’s her! Arrest that girl!","TWN":"嗯？是嫌犯！嫌犯出現！！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXTRA_NANA_B","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GUARD_EXTRA_NANA_B","text":{"KOREA":"승강장 방향으로 간다! 어서 잡아!!","JPN":"乗降場の方に向かっている！　今すぐ捕まえろ！！","ENG":"She’s headed towards the elevator! Cut her off, now!!","TWN":"往月台的方向移動！快去逮人！！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 이렇게 남은 분들만 잠시 기절시키면 돼요. 참 쉽죠?","JPN":"そして、残った方だけを気絶させればいいんです。簡単でしょう？","ENG":"Now, we just need to knock out the remaining guards. Easy, isn’t it?","TWN":"接下來就讓留在現場的人昏睡一下就好，很簡單對吧？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"후, 훌륭하구나! 역시 영입 대상 1호라면 이 정도는 해 줘야지!","JPN":"す、素晴らしいわ！　さすがスカウト対象第1号よ。これくらいはこなさなくっちゃね！","ENG":"M-marvelous! Now I want to recruit you even more!","TWN":"好…好厲害！真不愧是第一個要拉攏的對象！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"물론 나도 이런 간단한 유인책 정도는 떠올렸지만 말이다.","JPN":"もちろん、私もこれくらい簡単な陽動作戦は思いついてたわ。","ENG":"Of course, I also had a similar plan in mind...","TWN":"不過我剛也是有想到調虎離山之計啦～"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"와아, 역시 그럴 줄 알았어요!","JPN":"わあ、やっぱりそうだと思っていました！","ENG":"Yes, I knew you would too!","TWN":"哇～我就知道你也有想到！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그, 그래. 그렇지. 떠올렸고 말고.","JPN":"え、ええ、当り前じゃないの。","ENG":"Y-yeah... I had it all planned out...","TWN":"對…對啊，我當然也有想到！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"자, 그러면 다른 분들이 돌아오기 전에 어서 현장을 살펴 보죠.","JPN":"では、他の方々が戻ってくる前に、早く現場を調べてみましょう。","ENG":"Now, let’s examine the scene before the other guards come back.","TWN":"趁那些人還沒回來，我們趕快調查一下現場吧！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"흐음……. 이건 불에 녹은 흔적인가. 참 요란하게도 싸웠구나.","JPN":"ふーん……これは火で溶けた跡かしら。ずいぶん派手にやり合ってたみたいね。","ENG":"Hmm... It looks like fire melted everything down. Must’ve been one epic fight.","TWN":"嗯……這是被火融化的痕跡嗎？似乎是場激戰的樣子。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 카운터가 싸운 곳이니 이상하진 않다만…….","JPN":"まあ、カウンターが戦ったわけだから不思議ではないけれど……","ENG":"But, you know, it’s not unusual for a place where Counters have fought...","TWN":"不過，既然動手的是制裁者，那應該也不意外吧……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"음……? 이 쇳조각은……?","JPN":"ん……？　この鉄の破片は……？","ENG":"Mmm...? A shrapnel...?","TWN":"嗯……？這個鐵片是……？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어? 이건 탄두네요?","JPN":"あれ？　これは弾頭ですね。","ENG":"Huh? This is a bullet.","TWN":"嗯？這是彈頭？！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"탄두라고? 그럼 중요한 단서이지 않느냐!","JPN":"弾頭？　じゃあ重要な手がかりじゃないの！","ENG":"A bullet? Then it must be important evidence!","TWN":"彈頭？那不是很重要的線索嗎！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러게요. 왜 증거로 수집해 가지 않은 걸까요?","JPN":"そうですね。どうして証拠として収集されなかったのでしょう。","ENG":"I suppose... But why haven’t they collected it as evidence?","TWN":"是的，為什麼他們沒有把它當作證物帶走呢？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그, 그런 건 나중에 생각해 볼 일이지. 어서 살펴 보자꾸나.","JPN":"そ、そういうのは後で考えましょう。さっそく調べてみよう。","ENG":"T-that's not a matter to see now. Let’s first look around for more.","TWN":"這個問題之後再想吧，趕快再看看有沒有其他線索！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 네. 초원 씨에게 받은 알파 비전으로 탄두를 확대해 살펴보면…….","JPN":"はい。ナオさんから頂いたアルファビジョンで弾頭を拡大して調べると……","ENG":"Oh, yes. If we use Chowon’s Alpha Vision to get a close-up of the bullet...","TWN":"對了，這是初源借我的阿爾法願景，用它來放大看看……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"음, 음. 역시 그랬네요.","JPN":"うんうん、なるほど。やっぱりです。","ENG":"M-hmm... I knew it.","TWN":"嗯，果然是這樣。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이 탄두야말로 제가 범행을 저지를 수 없는 명백한 증거예요.","JPN":"この弾頭こそ、私の潔白を裏付ける証拠です。","ENG":"This bullet is clear evidence that I didn’t commit this crime.","TWN":"這顆彈頭完全可以證明我的清白。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"응? 뭔가 알아냈느냐?","JPN":"うん？　何かわかったのね？","ENG":"Hmm? Did you find something?","TWN":"什麼意思？你有發現什麼嗎？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 이 탄환에 남아 있는 탄조흔 때문이에요.","JPN":"ええ、この弾丸に残った線条痕を見ればわかります。","ENG":"Yes. Look at the ballistics left on the warhead.","TWN":"對，就是子彈內留下的彈痕。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"탄조…… 뭐?","JPN":"線条……何？","ENG":"The ball-what-now?","TWN":"彈……什麼？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"탄두가 강선에 긁힌 흔적이에요. 어떤 총에서 발사되었는지 알려 주는 총의 지문 같은 거죠.","JPN":"弾頭についた、銃身内の溝を通った痕のことです。\\n銃の種類を特定できる指紋のようなものですね。","ENG":"Look at the spiral markings on the bullet's side. Those marks, like a person's fingerprint, show which gun fired it.","TWN":"就是彈頭劃過膛線的痕跡。類似槍的指紋，可以知道是從哪種槍枝發射出來的。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아, 그렇지 참! 내가 잠깐 깜빡했구나!","JPN":"ああ、そうだったわね！　ちょっとど忘れしてたわ！","ENG":"Oh, that’s right! It must’ve slipped my mind!","TWN":"喔！對啦！我剛是一時忘記！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고……. 이 탄두에 새겨진 특유의 탄조흔은…….","JPN":"そして……この弾丸についた線条痕は……","ENG":"Now... by comparing the distinct markings on the side...","TWN":"根據……彈頭上的彈痕看來……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"틀림없이 제가 쓰는 총인 <color=#ffd34c>밸런스 브레이커</color>에서 발사된 흔적이에요!","JPN":"これは間違いなく、私の銃<color=#ffd34c>バランスブレイカー</color>からの発射痕です！","ENG":"And it matches the ballistics from my gun, the <color=#ffd34c>Balance Breaker</color>!","TWN":"可以確定，子彈是從我的槍<color=#ffd34c>平衡破壞者</color>發射出來的！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なんですって？","ENG":"W-what?","TWN":"你…你說什麼？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"틀림없어요. 이 총은 이노베이션을 세울 때 최대 주주님 요구로 저에게 맞춤 설계된 원 오프 타입이거든요.","JPN":"間違いありません。この銃はイノベーションを設立した際に、筆頭株主の要求で私専用に作られたワンオフタイプなんです。","ENG":"Without a doubt! This gun is a one-off custom weapon made by the majority shareholder and given to me on the day Innovation was established.","TWN":"沒錯，這把槍是當初創立改革時，根據股東的要求，專門為我量身打造的。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"프로모션을 겸한다지만 정식으로 생산된 건 아직까지 전 세계에 한 정뿐이에요.","JPN":"プロモーションも兼ねているそうですが、正式に生産されたのは世界でたった1丁だけです。","ENG":"Although it was also a promotional prototype, only one official copy of it exists in the world.","TWN":"雖然也想藉此行銷，但目前全世界就只有這麼一把。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"자, 잠깐만! 잠깐만 기다려라, 지아야!","JPN":"ちょ、ちょっと待って！　ユイちゃん！","ENG":"W-wait! Just hold on a second, Jia!","TWN":"等…你先等一下，小佳！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그럼 그 탄두는 네가 범행을 저질렀다는 명백한 증거 아니냐?","JPN":"それはつまり、その弾頭が君の犯行を裏付ける明白な証拠ってことじゃない？","ENG":"But doesn’t that clearly state that YOU committed the crime?","TWN":"那這不就表示犯人你是嗎？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 이 탄두를 찾았다면 감찰과 분들도 명백한 증거라고 생각했을 거예요.","JPN":"はい。監察課の方がこの弾頭を見つけていたら、きっと明白な証拠だと思ったでしょう。","ENG":"Yes, if Investigations had found this bullet, they would’ve had indisputable evidence that I pulled the trigger.","TWN":"是的，監察科的人如果有找到這顆彈頭，應該也會把它當作是鐵證。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 다른 분들과 함께 전철을 타고 돌아갔던 저에게는…….","JPN":"でも、皆さんと一緒に電車で帰っていた私には……","ENG":"But as I was on the subway heading back home with the others that night...","TWN":"但是對於那天晚上和其他人一起搭地鐵的我而言……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"범인이 또 하나의 밸런스 브레이커를 사용해 저에게 누명을 씌우려 했다는 증거로 보여요.","JPN":"犯人がもう一つのバランスブレイカーを使って、私に濡れ衣を着せようとした証拠に見えます。","ENG":"I think the suspect is using another Balance Breaker to frame everything on me.","TWN":"這就證明，犯人是使用另一個平衡破壞者，然後想要栽贓給我。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"하지만 네 능력이 있지 않느냐?","JPN":"でも、君には能力があるじゃないの。","ENG":"But what about your ability, then?","TWN":"但不是有你的能力嗎？"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그 총기도 똑같이 재현해 버리면…….","JPN":"その銃器も同じように再現してしまえば……","ENG":"You could make an exact copy of that gun, and...","TWN":"要完全複製那把槍的話……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"재현은 가능하지만, 능력을 해제하면 구현된 물체도 그대로 사라져 버려요.","JPN":"再現はできますが、能力を解除すると具現化された物体もそのまま消滅してしまいます。","ENG":"I could, but once I stop using my ability, anything that I augmented will disappear.","TWN":"是可以複製，但解除能力的話，複製出來的東西也會消失不見。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 그런 짓을 저질렀다면 이런 증거를 남길 만큼 허술하지도 않았을 거고요.","JPN":"それに私がするのであれば、こんな証拠を残すようなことはしなかったはずです。","ENG":"Even if I did commit this crime, I'm not that clumsy to leave anything behind that could lead back to me.","TWN":"如果我真的要做這種事，才不會犯這種愚蠢的錯誤，還留下證據。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그렇다면…… 이 탄두는 실물에서 발사됐다는 뜻이구나.","JPN":"ということは……この弾頭は実物から発射されたということなのね。","ENG":"Then... That means this bullet was fired from the real thing.","TWN":"意思就是……這個彈頭是從真的槍枝裡發射出來的。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 변장할 수 있는 방법은 다양하지만, 밸런스 브레이커만큼은 생산할 방법이 매우 제한적이에요.","JPN":"はい。銃の製造方法は様々ですが、バランスブレイカーだけはごく限られた方法でしか作れません。","ENG":"Correct. Anyone could disguise to look like me, but producing another Balance Breaker narrows our search significantly.","TWN":"沒錯，雖然有很多方法可以仿造，但平衡破壞者的生產方法非常受限。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다시 말해 밸런스 브레이커의 <color=#ffd34c>공급로</color>를 찾으면 범인의 행방도 쫓을 수 있다는 뜻이죠!","JPN":"言い換えれば、バランスブレイカーの<color=#ffd34c>供給路</color>をたどれば、犯人も突き止められるということになりますね！","ENG":"In other words, if we track down the Balance Breaker's <color=#ffd34c>supply route</color>, we’ll be able to find the culprit’s whereabouts!","TWN":"也就是說，只要找到平衡破壞者<color=#ffd34c>貨源</color>，就可以找到犯人的下落！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"오호라……!","JPN":"なるほど……！","ENG":"Ooooh...!","TWN":"嗚啦啦……！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스 내부에 밸런스 브레이커의 제작에 관여했던 계열사는 모두 세 곳.","JPN":"アルファトリックスの内部でバランスブレイカーの製造に関わった系列会社は全部で3社。","ENG":"There are only three facilities in Alphatrix that are involved in the Balance Breaker’s production.","TWN":"在阿爾法崔克斯內部，參與製造平衡破壞者的相關企業一共有3間。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"총기 생산을 맡은 <color=#ffd34c>메카닉스</color>.","JPN":"銃器製造部門の<color=#ffd34c>メカニックス</color>。","ENG":"<color=#ffd34c>Mechanics</color>, where the manufacturing of guns is done.","TWN":"分別是，負責製造槍枝的<color=#ffd34c>機械</color>，"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"탑재된 AI 모듈의 생산을 맡은 <color=#ffd34c>일렉트로닉스</color>…….","JPN":"搭載されるAIモジュールの生産を担当した<color=#ffd34c>エレクトロニクス</color>……","ENG":"<color=#ffd34c>Electronics</color>, where the AI modules for it are made...","TWN":"負責生產槍枝內AI模組的<color=#ffd34c>電子</color>……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마지막으로, 특수탄 생산을 맡은 <color=#ffd34c>헤비암즈</color>.","JPN":"最後に、特殊弾の製造部門である<color=#ffd34c>ヘビーアームズ</color>。","ENG":"And finally, <color=#ffd34c>Heavyarms</color>, where the custom munition is made.","TWN":"和負責生產特殊彈的<color=#ffd34c>重武裝</color>。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"틀림없이 이 세 회사 중에 실마리가 있을 거예요!","JPN":"この3社を調べれば、きっと手がかりが見つかるはずです！","ENG":"One of these three companies should lead us to another clue!","TWN":"線索一定就在這3間公司之中！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};